// Parse input from toolWorkflow v2.2
// autoMapInputData sends the tool call's input string as {query: "..."}
const raw = $input.first().json;

// toolWorkflow wraps the AI Agent's tool input in "query" or "input" field
let parsed = raw;
const inputStr = raw.query || raw.input || raw.chatInput;

if (typeof inputStr === "string") {
  try { parsed = JSON.parse(inputStr); } catch(e) { parsed = raw; }
} else if (inputStr && typeof inputStr === "object") {
  parsed = inputStr;
}

const apiName = parsed.api_name;
const action = parsed.action;
const tenantId = parsed.tenant_id || $vars.DEFAULT_TENANT_ID || "kahuna";
let params = parsed.params || {};

if (typeof params === "string") {
  try { params = JSON.parse(params); } catch(e) { params = {}; }
}

if (!apiName || !action) {
  return [{ json: { error: "Missing required fields: api_name and action", received: JSON.stringify(raw).substring(0, 500) } }];
}

try {
  const response = await this.helpers.httpRequest({
    method: "POST",
    url: `${$vars.N8N_API_URL}/webhook/orchestrate-v2`,
    headers: {
      "Content-Type": "application/json",
      "x-api-key": $vars.key_master
    },
    body: {
      domain: apiName,
      action: action,
      client: tenantId,
      params: params
    },
    json: true,
    timeout: 55000
  });

  const str = JSON.stringify(response);
  if (str.length > 15000) {
    const data = response.data || response.result || response;
    const items = Array.isArray(data) ? data : (data.rows || data.results || data.items || [data]);
    return [{ json: { _truncated: true, _total: items.length, data: items.slice(0, 20) } }];
  }
  return [{ json: response }];
} catch(e) {
  return [{ json: { error: e.message || String(e) } }];
}
